import { useState, useEffect } from "react";
import { Link, useLocation, useNavigate } from "react-router-dom";
import "../App.css";
import API from "../api/axios";

/* ==========================================================
   NAVIGATION COMPONENT
========================================================== */
function Nav() {

  const location = useLocation();

  const applyTheme = (mode) => {
    const body = document.body;

    if (mode === "dark") {
      body.classList.add("dark-mode");
      localStorage.setItem("user-theme", "dark");
    } else {
      body.classList.remove("dark-mode");
      localStorage.setItem("user-theme", "light");
    }

    window.dispatchEvent(new Event("storage"));
  };

  useEffect(() => {

    const savedTheme = localStorage.getItem("user-theme");
    const systemPrefersDark =
      window.matchMedia("(prefers-color-scheme: dark)").matches;

    if (savedTheme === "dark") applyTheme("dark");
    else if (savedTheme === "light") applyTheme("light");
    else applyTheme(systemPrefersDark ? "dark" : "light");

  }, []);

  const toggleTheme = () => {
    const isDark = document.body.classList.contains("dark-mode");
    applyTheme(isDark ? "light" : "dark");
  };

  const isActive = (path) =>
    location.pathname === path ? "active" : "";

  return (
    <header>

      <h1 className="title">
        Expressing Creativity Through Art and Crafts
      </h1>

      <nav className="menu">

        <Link to="/home" className={isActive("/home")}>HOME</Link>
        <Link to="/about" className={isActive("/about")}>ABOUT</Link>
        <Link to="/contact" className={isActive("/contact")}>CONTACT US</Link>
        <Link to="/register" className={isActive("/register")}>REGISTER</Link>

        <button className="theme-btn" onClick={toggleTheme}>
          ☀️🌙
        </button>

      </nav>

    </header>
  );
}

/* ==========================================================
   REGISTER PAGE
========================================================== */

function RegisterPage() {

  const navigate = useNavigate();

  const [formData, setFormData] = useState({
    fullName: "",
    email: "",
    password: "",
    confirmPassword: "",
    terms: false
  });

  const [errors, setErrors] = useState({});
  const [errorMsg, setErrorMsg] = useState("");
  const [successMessage, setSuccessMessage] = useState("");

  const [showPassword, setShowPassword] = useState(false);
  const [showConfirmPassword, setShowConfirmPassword] = useState(false);

  /* =============================
     HANDLE INPUT CHANGE
  ============================= */

  const handleChange = (e) => {

    const { name, value, type, checked } = e.target;

    setFormData((prev) => ({
      ...prev,
      [name]: type === "checkbox" ? checked : value
    }));

  };

  /* =============================
     FORM VALIDATION
  ============================= */

  const validateForm = () => {

    let newErrors = {};

    if (!formData.fullName.trim())
      newErrors.fullName = "Full name is required";

    if (!formData.email.includes("@"))
      newErrors.email = "Valid email is required";

    if (formData.password.length < 6)
      newErrors.password = "Password must be at least 6 characters";

    if (formData.password !== formData.confirmPassword)
      newErrors.confirmPassword = "Passwords do not match";

    if (!formData.terms)
      newErrors.terms = "You must agree to the terms";

    setErrors(newErrors);

    return Object.keys(newErrors).length === 0;
  };

  /* =============================
     SUBMIT FORM
  ============================= */

  const handleSubmit = async (e) => {

    e.preventDefault();

    setErrorMsg("");
    setSuccessMessage("");

    if (!validateForm()) return;

    try {

      const payload = {
        name: formData.fullName,
        email: formData.email,
        password: formData.password
      };

      const { data } = await API.post("/auth/register", payload);

      localStorage.setItem("token", data.token);

      setSuccessMessage("Registration successful!");

      setTimeout(() => {
        navigate("/home");
      }, 1500);

    } catch (err) {

      setErrorMsg(
        err.response?.data?.message || "Registration failed."
      );

    }

  };

  const alignedLabel = {
    display: "flex",
    alignItems: "center",
    gap: "8px",
    cursor: "pointer"
  };

  return (
    <>
      <Nav />

      <main className="content-wrapper">

        <div className="register-intro">
          <h2>Join My Art & Crafts Community</h2>
          <p>Let’s connect and create!</p>
        </div>

        <section className="register-layout">

          {/* LEFT SIDE */}
          <div className="why-signup-box">

            <h3>Why Sign Up?</h3>

            <p>
              Get updates about creative art ideas, craft tutorials,
              and inspiration.
            </p>

            <img
              src="/pictures/paint5.png"
              alt="Art inspiration"
              className="decorative-img"
            />

          </div>

          {/* FORM */}
          <div className="form-container">

            <form className="register-form" onSubmit={handleSubmit}>

              {errorMsg && (
                <p className="error-message">{errorMsg}</p>
              )}

              {successMessage && (
                <p className="success-message">{successMessage}</p>
              )}

              <div className="form-group">
                <label>Full Name</label>
                <input
                  type="text"
                  name="fullName"
                  value={formData.fullName}
                  onChange={handleChange}
                />
                <span className="error-message">{errors.fullName}</span>
              </div>

              <div className="form-group">
                <label>Email</label>
                <input
                  type="email"
                  name="email"
                  value={formData.email}
                  onChange={handleChange}
                />
                <span className="error-message">{errors.email}</span>
              </div>

              <div className="form-group password-wrapper">

                <label>Password</label>

                <input
                  type={showPassword ? "text" : "password"}
                  name="password"
                  value={formData.password}
                  onChange={handleChange}
                />

                <button
                  type="button"
                  className="toggle-icon"
                  onClick={() => setShowPassword(!showPassword)}
                >
                  👁
                </button>

                <span className="error-message">{errors.password}</span>

              </div>

              <div className="form-group password-wrapper">

                <label>Confirm Password</label>

                <input
                  type={showConfirmPassword ? "text" : "password"}
                  name="confirmPassword"
                  value={formData.confirmPassword}
                  onChange={handleChange}
                />

                <button
                  type="button"
                  className="toggle-icon"
                  onClick={() =>
                    setShowConfirmPassword(!showConfirmPassword)
                  }
                >
                  👁
                </button>

                <span className="error-message">
                  {errors.confirmPassword}
                </span>

              </div>

              <div className="form-group checkbox-group">

                <label style={alignedLabel}>
                  <input
                    type="checkbox"
                    name="terms"
                    checked={formData.terms}
                    onChange={handleChange}
                  />
                  I agree to the terms and conditions
                </label>

                <span className="error-message">{errors.terms}</span>

              </div>

              <div className="button-wrapper">
                <button type="submit" className="register-submit">
                  Register
                </button>
              </div>

            </form>

          </div>

        </section>

      </main>

      <footer>
        <div className="footer-content">
          <span>📧 email: deveraclaire00@gmail.com</span>
          <span>© 2026 Claire Denise De Vera - Student Portfolio Project</span>
        </div>
      </footer>
    </>
  );
}

export default RegisterPage;
